func TestBasicRequirements(t *testing.T) {
	data, err := os.ReadFile("cas.go")
	if err != nil {
		t.Fatal(err)
	}
	sourceCode := string(data)

	// requirement - This means channels or the "sync" package is forbidden.
	if strings.Contains(sourceCode, `"sync"`) {
		t.Error("sync package is not allowed")
	}
	if strings.Contains(sourceCode, `chan`) {
		t.Error("channels are not allowed")
	}

	// requirement - Do not store the entire contents of a file in memory for any length of time.
	for _, s := range []string{`io.ReadAll`, `io.ReadFull`, `os.ReadFile`} {
		if strings.Contains(sourceCode, s) {
			t.Errorf("%q function tends to be used to read the entire contents of an io.Reader", s)
		}
	}

	// []byte is also bad but people might use it for a small temporary buffer
	for _, s := range []string{`bytes.`, `os.WriteFile`} {
		if strings.Contains(sourceCode, s) {
			t.Errorf("%s is not actually necessary to complete this assignment and often leads to putting the entire file contents into memory.  Consider using io.Copy, io.Reader, and io.Writer instead.", s)
		}
	}

	// NOTE testing that the state of the CAS struct is concurrency safe is not possible without inspecting the source code manually.
}

func TestNew(t *testing.T) {
	cas, err := New(t.TempDir(), "sha256", "sha384", "sha512", "sha512-224", "sha512-256")
	if err != nil {
		t.Fatal(err)
	}
	if cas == nil {
		t.Error("Expected cas to be non-nil")
	}

	_, err = New(t.TempDir(), "sha255")
	if !errors.Is(err, ErrInvalidDigest) {
		t.Fatal("Expected invalid digest error")
	}
}

func upload(t *testing.T, ts *httptest.Server, filename string, digests map[string]string) {
	t.Helper()
	f, err := os.Open(filename)
	if err != nil {
		t.Fatal(err)
	}
	defer f.Close()

	res, err := http.Post(ts.URL+"/blob/", "application/octet-stream", f)
	if err != nil {
		t.Fatal(err)
	}
	defer res.Body.Close()

	if res.StatusCode != http.StatusOK {
		t.Fatalf("Bad status code: %d", res.StatusCode)
	}

	body, err := io.ReadAll(res.Body)
	if err != nil {
		t.Fatal(err)
	}
	err = res.Body.Close()
	if err != nil {
		t.Fatal(err)
	}

	t.Logf("Upload headers %v", res.Header)
	for name, value := range digests {
		if res.Header.Get("X-Digest-"+name) != value {
			t.Errorf("Wrong %s digest", name)
		}
	}

	if len(body) != 0 {
		t.Error("Expected an empty body")
	}
}

