func TestBlobGet(t *testing.T) { //nolint:gocognit
	storageDir := t.TempDir()

	func() {
		cas, err := New(storageDir, "sha256", "sha512", "sha512-256")
		if err != nil {
			t.Fatal(err)
		}
		ts := httptest.NewServer(cas)
		defer ts.Close()
		upload(t, ts, filepath.Join("testdata", "Green eggs and ham"), nil)
		upload(t, ts, filepath.Join("testdata", "The cat in the hat"), nil)
	}()

	// Start fresh server to make sure memory state is cleared
	cas, err := New(storageDir, "sha256", "sha512", "sha512-256")
	if err != nil {
		t.Fatal(err)
	}
	ts := httptest.NewServer(cas)
	defer ts.Close()

	t.Run("GET", func(t *testing.T) {
		res, err := http.Get(ts.URL + "/blob/sha256/ebd5ebca1e23f983f7e06035ec34c501125971c954d9478f4964eafd0ff040bb")
		if err != nil {
			t.Fatal(err)
		}
		body, err := io.ReadAll(res.Body)
		res.Body.Close()
		if err != nil {
			t.Fatal(err)
		}

		if res.StatusCode != http.StatusOK {
			t.Fatal("Bad status code", res)
		}

		t.Logf("Download headers %v", res.Header)
		if ct := res.Header.Get("Content-Type"); ct != "application/octet-stream" {
			t.Error("Invalid content-type:", ct)
		}
		if len(body) != 3461 {
			t.Logf("Wrong content length.  %d != 3461", len(body))
		}

		if bytes.HasPrefix(body, []byte("GREEN EGGS AND HAM")) {
			t.Errorf("Unexpected body.  Got %s but wanted \"Green Eggs and Ham\"", string(body))
		}
	})

	t.Run("HEAD File2", func(t *testing.T) {
		res, err := http.Head(ts.URL + "/blob/sha512/b50d67fe687078f3c348bb0e562354d2191c522d6d50e31427d43aecafdf89928dcd62b9737484b2e241f13c335aebd11e544dfd2b165b92355262003b04632a")
		if err != nil {
			t.Fatal(err)
		}
		_, err = io.ReadAll(res.Body)
		res.Body.Close()
		if err != nil {
			t.Fatal(err)
		}

		if res.StatusCode != http.StatusOK {
			t.Fatal("Bad status code", res)
		}

		t.Logf("Download headers %v", res.Header)
		if res.ContentLength != 0 {
			t.Log("Body should be empty")
		}
	})
}

func TestStats(t *testing.T) {
	storageDir := t.TempDir()

	{
		t.Log("populating")
		cas, err := New(storageDir, "sha256", "sha512")
		if err != nil {
			t.Fatal(err)
		}
		ts := httptest.NewServer(cas)
		defer ts.Close()

		// try uploading some data
		upload(t, ts, filepath.Join("testdata", "Green eggs and ham"), nil)
		upload(t, ts, filepath.Join("testdata", "The cat in the hat"), nil)
		upload(t, ts, filepath.Join("testdata", "greeting"), nil)
		upload(t, ts, filepath.Join("testdata", "another"), nil)
		upload(t, ts, filepath.Join("testdata", "another"), nil)
		upload(t, ts, filepath.Join("testdata", "Green eggs and ham"), nil)
	}

	t.Run("Deduplication", func(t *testing.T) {
		storageSize, err := du(os.DirFS(storageDir))
		if err != nil {
			t.Fatal(err)
		}

		// File sizes of the test data
		var expectedSize int64 = 3461 + 7458 + 13 + 11
		if storageSize != expectedSize {
			t.Errorf("Data in the storage directory is %d B but expected %d B", storageSize, expectedSize)
		}
	})

	// create a new CAS to ensure that there is no state in the server itself.
	// All state should be in the filesystem
	cas, err := New(storageDir, "sha256", "sha512")
	if err != nil {
		t.Fatal(err)
	}
	ts := httptest.NewServer(cas)
	defer ts.Close()

	res, err := http.Get(ts.URL + "/stats/")
	if err != nil {
		t.Fatal(err)
	}

	if res.StatusCode != http.StatusOK {
		t.Fatal("Bad status code", res)
	}

	t.Logf("Stats headers %v", res.Header)
	if res.Header.Get("Content-Type") != "application/json" {
		t.Error("Invalid content-type", res.Header.Get("Content-Type"))
	}

	stats := struct {
		Count  int64
		Mean   float64
		Stddev float64
	}{}

	err = json.NewDecoder(res.Body).Decode(&stats)
	if err != nil {
		t.Fatal(err)
	}
	err = res.Body.Close()
	if err != nil {
		t.Fatal(err)
	}

	t.Logf("%+v", stats)
	if stats.Count != 4 {
		t.Error("Count is wrong")
	}
	if math.Abs(stats.Mean-2735.75) > 0.1 {
		t.Errorf("Mean is incorrect")
	}
	if math.Abs(stats.Stddev-3068.5) > 0.1 {
		t.Errorf("Standard deviation is incorrect")
	}
}

func du(fsys fs.FS) (int64, error) {
	var size int64
	seen := make(map[uint64]string)

	return size, fs.WalkDir(fsys, ".", func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}

		if d.IsDir() {
			return nil
		}

		fi, err := d.Info()
		if err != nil {
			return err //nolint:wrapcheck
		}

		if fi.Mode()&os.ModeSymlink == os.ModeSymlink {
			return nil
		}

		// extract the inode number (UNIX only)
		inode := fi.Sys().(*syscall.Stat_t).Ino

		_, ok := seen[inode]
		if ok {
			// duplicate inode number, skip
			return nil
		}
		seen[inode] = path
		size += fi.Size()

		return nil
	})
}

func TestDU(t *testing.T) {
	// Test my test code

	d := t.TempDir()

	// add some files directories
	err := os.Mkdir(filepath.Join(d, "subdir"), 0777)
	if err != nil {
		t.Fatal(err)
	}

	err = os.WriteFile(filepath.Join(d, "file1"), []byte("the data"), 0666)
	if err != nil {
		t.Fatal(err)
	}

	err = os.WriteFile(filepath.Join(d, "subdir", "file2"), []byte("in sub dir"), 0666)
	if err != nil {
		t.Fatal(err)
	}

	err = os.Symlink(filepath.Join(d, "file1"), filepath.Join(d, "symlink-to-file1"))
	if err != nil {
		t.Fatal(err)
	}

	err = os.Link(filepath.Join(d, "subdir", "file2"), filepath.Join(d, "hardlink-to-file2"))
	if err != nil {
		t.Fatal(err)
	}

	var size int64
	size, err = du(os.DirFS(d))
	if err != nil {
		t.Fatal(err)
	}

	if size != 8+10 {
		t.Errorf("expected 18 B but got %d B", size)
	}
}
